class Solution:
    def isValidSudoku(self, board: List[List[str]]) -> bool:
        rows=cols=boxes=[set() for _ in range(9)]
        for r in range(9):
            for c in range(9):
                v=board[r][c]
                if v=='.': continue
                b=(r//3)*3+c//3
                if v in rows[r] or v in cols[c] or v in boxes[b]: return False
                rows[r].add(v); cols[c].add(v); boxes[b].add(v)
        return True

